DROP TABLE IF EXISTS `shipping_bills`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `shipping_bills` (
  `id` int NOT NULL AUTO_INCREMENT,
  `sb_no` varchar(50) COLLATE utf8mb4_general_ci NOT NULL,
  `consignment_id` int DEFAULT NULL,
  `entered_date` date DEFAULT NULL,
  `status` varchar(20) COLLATE utf8mb4_general_ci DEFAULT 'DRAFT',
  `approved_by` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `approved_at` datetime DEFAULT NULL,
  `remarks` text COLLATE utf8mb4_general_ci,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `shipping_bill_no` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `shipping_bill_date` date DEFAULT NULL,
  `flight_no` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `etd` date DEFAULT NULL,
  `vt` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `port_of_discharge` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `country_of_destination` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `station` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `exporter_name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `exporter_address` text COLLATE utf8mb4_general_ci,
  `entered_no` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `branch_id` int DEFAULT NULL,
  `unapproved_by` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `unapproved_at` datetime DEFAULT NULL,
  `unapproved_remarks` text COLLATE utf8mb4_general_ci,
  `sb_date` date DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `sb_no` (`sb_no`),
  KEY `consignment_id` (`consignment_id`),
  CONSTRAINT `shipping_bills_ibfk_1` FOREIGN KEY (`consignment_id`) REFERENCES `consignments` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=50 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
